decimal TotalPercentageChicksSettedEggs  = 0;
decimal TotalPercentageChicksVsFert  = 0;
decimal TotalPercentageChicksSettedVsFert = 0;
private void xrTableCell18_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal chicks = 0;
decimal chicksSettedEggs = 0;

// --- Accumulators for totals ---
decimal totalReportChicks = 0;
decimal totalReportChicksSettedEggs = 0;

// --- Chicks ---
if (GetCurrentColumnValue("Chicks") != null)
    chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));
totalReportChicks += chicks;

// --- ChicksSettedEggs ---
if (GetCurrentColumnValue("ChicksSettedEggs") != null)
    chicksSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("ChicksSettedEggs"));
totalReportChicksSettedEggs += chicksSettedEggs;

// --- Equation (row level %) ---
decimal percentage = 0;
if (chicksSettedEggs != 0)
    percentage = (chicks * 100m) / chicksSettedEggs;

// --- Total percentage ---
if (totalReportChicksSettedEggs != 0)
    TotalPercentageChicksSettedEggs = (totalReportChicks * 100m) / totalReportChicksSettedEggs;

// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00");  // Row level %
}

private void xrTableCell37_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      xrTableCell37.Text = TotalPercentageChicksSettedEggs.ToString("0");
      TotalPercentageChicksSettedEggs  = 0; // reset for next group

}

