private void xrTableCell22_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal chicks = 0;
decimal chicksSettedEggs = 0;
decimal fertPer = 0;

// --- Accumulators for totals ---
decimal totalReportChicks = 0;
decimal totalReportChicksSettedEggs = 0;
decimal totalReportFertPer = 0;

// --- Chicks ---
if (GetCurrentColumnValue("Chicks") != null)
    chicks = Convert.ToDecimal(GetCurrentColumnValue("Chicks"));
totalReportChicks += chicks;

// --- ChicksSettedEggs ---
if (GetCurrentColumnValue("ChicksSettedEggs") != null)
    chicksSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("ChicksSettedEggs"));
totalReportChicksSettedEggs += chicksSettedEggs;

// --- FertPer ---
if (GetCurrentColumnValue("FertPer") != null)
    fertPer = Convert.ToDecimal(GetCurrentColumnValue("FertPer"));
totalReportFertPer += fertPer;

// --- Equation (row level %) ---
decimal percentage = 0;
if (fertPer != 0 && chicksSettedEggs != 0)
    percentage = ((chicks * 100m / chicksSettedEggs) / fertPer) * 100m;

// --- Total percentage ---
if (totalReportFertPer != 0 && totalReportChicksSettedEggs != 0)
    TotalPercentageChicksVsFert = ((totalReportChicks * 100m / totalReportChicksSettedEggs) / totalReportFertPer) * 100m;

// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.00");  // Row level %
}

private void xrTableCell41_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare values ---
decimal chicksSettedEggs = 0;
decimal fertileEggs = 0;
decimal fertPer = 0;

// --- Accumulators for totals ---
decimal totalReportChicksSettedEggs = 0;
decimal totalReportFertileEggs = 0;
decimal totalReportFertPer = 0;

// --- ChicksSettedEggs ---
if (GetCurrentColumnValue("ChicksSettedEggs") != null)
    chicksSettedEggs = Convert.ToDecimal(GetCurrentColumnValue("ChicksSettedEggs"));
totalReportChicksSettedEggs += chicksSettedEggs;

// --- FertileEggs ---
if (GetCurrentColumnValue("FertileEggs") != null)
    fertileEggs = Convert.ToDecimal(GetCurrentColumnValue("FertileEggs"));
totalReportFertileEggs += fertileEggs;

// --- FertPer ---
if (GetCurrentColumnValue("FertPer") != null)
    fertPer = Convert.ToDecimal(GetCurrentColumnValue("FertPer"));
totalReportFertPer += fertPer;

// --- Equation (row level %) ---
decimal percentage = 0;
if (fertPer != 0)
{
    if (totalReportChicksSettedEggs != 0)
        percentage = (chicksSettedEggs * 100m) / ((fertileEggs * 100m) / totalReportChicksSettedEggs);
}

// --- Total percentage ---
if (totalReportFertPer != 0 && totalReportChicksSettedEggs != 0)
    TotalPercentageChicksSettedVsFert = (totalReportChicksSettedEggs * 100m) /
                                        ((totalReportFertileEggs * 100m) / totalReportChicksSettedEggs);

// --- Assign row % to the cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = TotalPercentageChicksSettedVsFert.ToString("0.00");  // Row level %

}
